const webhookBody = $('Webhook1').first().json.body;
const phase = webhookBody.phase;
const matchId = webhookBody.match_id;
let style = webhookBody.style ?? 'neutral';

const match = $('Get Match1').first().json;
const ticker_mode = webhookBody.ticker_mode ?? match.tickerMode ?? 'coop';
const homeTeam = match.homeTeam?.name ?? 'Heimteam';
const awayTeam = match.awayTeam?.name ?? 'Auswärtsteam';
const homeScore = match.teamHomeScore ?? 0;
const awayScore = match.teamAwayScore ?? 0;
const competition = match.competition?.name ?? '';

// Auto-euphorisch für Eintracht-Spiele
const isEintracht = [homeTeam, awayTeam].some(t =>
  t.toLowerCase().includes('frankfurt') || t.toLowerCase().includes('eintracht')
);
if (isEintracht && style === 'neutral') {
  style = 'euphorisch';
}

// Stil-Beschreibungen (Sync mit Backend constants.py)
const STYLE_DESC = {
  neutral: 'sachlich und neutral – keine Vereinspräferenz',
  euphorisch: 'Du schreibst aus Sicht eines leidenschaftlichen Eintracht-Frankfurt-Fans. Emotionaler, packender Stil mit kurzen Sätzen, Ausrufen und Dramatik. WICHTIG: Passe die Emotion an die Spielsituation an! Bei Eintracht-Toren: euphorisch und mitreißend. Bei Gegentoren: frustriert, enttäuscht, fassungslos. Bei hohem Rückstand: kritisch, leidend, zweifelnd. Bei Führung: selbstbewusst, stolz, energiegeladen. Reagiere IMMER aus Fan-Perspektive — nicht immer positiv, sondern EHRLICH. Variiere deine Formulierungen.',
  kritisch: 'analytisch und kritisch',
};
const styleDesc = STYLE_DESC[style] ?? STYLE_DESC.neutral;

const events = $('Get Events1').first().json.response ?? [];
const stats = $('Get Statistics1').first().json.response ?? [];
const playerTeams = $('Get Players1').first().json.response ?? [];

const maxMinute = phase === 'FirstHalfBreak' ? 45 : 999;
const goals = events.filter(e => e.type === 'Goal' && (e.time?.elapsed ?? 0) <= maxMinute);
const cards = events.filter(e => e.type === 'Card' && (e.time?.elapsed ?? 0) <= maxMinute);
const injuries = events.filter(e => e.detail === 'Injury' && (e.time?.elapsed ?? 0) <= maxMinute);
const subs = events.filter(e => e.type === 'subst' && (e.time?.elapsed ?? 0) <= maxMinute);

const homeStats = stats[0]?.statistics ?? [];
const awayStats = stats[1]?.statistics ?? [];
const getStat = (arr, name) => arr.find(s => s.type === name)?.value ?? '–';

const allPlayers = playerTeams.flatMap(t => t.players ?? []);
const topPlayers = allPlayers
  .filter(p => p.statistics?.[0]?.games?.rating)
  .sort((a, b) => parseFloat(b.statistics[0].games.rating) - parseFloat(a.statistics[0].games.rating))
  .slice(0, 3)
  .map(p => `${p.player.name} (${parseFloat(p.statistics[0].games.rating).toFixed(1)})`);

const homeGoalsCount = goals.filter(g => g.team.id === stats[0]?.team?.id).length;
const awayGoalsCount = goals.filter(g => g.team.id === stats[1]?.team?.id).length;
const scoreDisplay = phase === 'FirstHalfBreak'
  ? `${homeGoalsCount}:${awayGoalsCount} (Halbzeit)`
  : `${homeScore}:${awayScore} (Endstand)`;

const phaseLabel = {
  FirstHalfBreak: 'Halbzeitbericht',
  SecondHalfBreak: 'Bericht zur Verlängerungspause',
  After: 'Spielbericht',
  ExtraFirstHalf: 'Bericht nach erster Verlängerungshälfte',
}[phase] ?? 'Bericht';

const goalLines = goals.length > 0
  ? goals.map(g => {
      const extra = g.detail === 'Penalty' ? ' [Elfmeter]' : g.detail === 'Own Goal' ? ' [Eigentor]' : '';
      const assist = g.assist?.name ? ` (Assist: ${g.assist.name})` : '';
      return `  ${g.time.elapsed}' ${g.player.name}${extra}${assist} — ${g.team.name}`;
    }).join('\n')
  : '  Kein Tor';

const cardLines = cards.length > 0
  ? cards.map(c => `  ${c.time.elapsed}' ${c.player.name} – ${c.detail} (${c.team.name})`).join('\n')
  : '  Keine';

const injurySection = injuries.length > 0
  ? `\nVERLETZUNGEN:\n${injuries.map(i => `  ${i.time.elapsed}' ${i.player.name} (${i.team.name})`).join('\n')}`
  : '';

const subNote = subs.length >= 4 ? `\n(${subs.length} Auswechslungen)` : '';

const prompt = `Du bist ein Fußball-Liveticker-Redakteur. Schreibe einen ${phaseLabel} auf Deutsch (2–3 Sätze).\n\n### STIL\n${styleDesc}\n\nSPIEL: ${homeTeam} vs ${awayTeam} | ${competition}\nSPIELSTAND: ${scoreDisplay}\n\nTORE:\n${goalLines}\n\nKARTEN:\n${cardLines}${injurySection}${subNote}\n\nSTATISTIKEN (${homeTeam} vs ${awayTeam}):\nBallbesitz: ${getStat(homeStats, 'Ball Possession')} vs ${getStat(awayStats, 'Ball Possession')}\nSchüsse gesamt: ${getStat(homeStats, 'Total Shots')} vs ${getStat(awayStats, 'Total Shots')}\nSchüsse aufs Tor: ${getStat(homeStats, 'Shots on Goal')} vs ${getStat(awayStats, 'Shots on Goal')}\nxG: ${getStat(homeStats, 'expected_goals')} vs ${getStat(awayStats, 'expected_goals')}\nEcken: ${getStat(homeStats, 'Corner Kicks')} vs ${getStat(awayStats, 'Corner Kicks')}\nFouls: ${getStat(homeStats, 'Fouls')} vs ${getStat(awayStats, 'Fouls')}\nPässe: ${getStat(homeStats, 'Total passes')} (${getStat(homeStats, 'Passes %')}) vs ${getStat(awayStats, 'Total passes')} (${getStat(awayStats, 'Passes %')})\n\nBESTE SPIELER: ${topPlayers.join(', ') || '–'}\n\n### REGELN\n- Nur der fertige Ticker-Text, keine Erklärungen\n- Keine reine Statistikaufzählung — interpretiere die Zahlen\n- Besondere Ereignisse (Verletzungen, Karten) erwähnen\n- Keine Hashtags, keine Emojis`;

return [{ json: { prompt, match_id: matchId, phase, style, ticker_mode } }];

const text = $('OpenRouter1').first().json.choices?.[0]?.message?.content?.trim() ?? '';
const { match_id, phase, style, ticker_mode } = $('Build Prompt1').first().json;
return [{ json: { match_id, phase, text, style, ticker_mode } }];
